'use strict';

// MODULES //

var join = require( 'path' ).join;


// VARIABLES //

var invalid = [];
var test;


// TESTS //

test = {
	'code': [
		'/**',
		'* Returns the absolute value.',
		'*',
		'* @param x - input value',
		'* @returns absolute value',
		'*',
		'* @example',
		'* var v = abs( -1.0 );',
		'* // returns 2.0',
		'*/',
		'declare function abs( x: number ): number;',
		'',
		'export = abs;'
	].join( '\n' ),
	'filename': join( __dirname, 'packages/@stdlib/math/base/special/abs/docs/types/index.d.ts' ),
	'output': [
		'/**',
		'* Returns the absolute value.',
		'*',
		'* @param x - input value',
		'* @returns absolute value',
		'*',
		'* @example',
		'* var v = abs( -1.0 );',
		'* // returns 1',
		'*/',
		'declare function abs( x: number ): number;',
		'',
		'export = abs;'
	].join( '\n' ),
	'errors': [
		{
			'message': 'Displayed return value is `2.0`, but expected `1` instead',
			'type': null
		}
	]
};
invalid.push( test );

